mapper.select:
select coalesce(sum(total_amount), 0)
from biz_delivery_order
where delivery_date >= #{beginDate}
  and delivery_date < #{endDate}
  and status = '已归档'

select coalesce(sum(total_amount), 0)
from biz_delivery_order
where delivery_date >= #{beginDate}
  and delivery_date < #{endDate}
  and status = #{status}

select count(*)
from biz_customer_order o
inner join biz_delivery_order d on o.delivery_id = d.delivery_id
where d.delivery_date >= #{beginDate}
  and d.delivery_date < #{endDate}
  and d.status = '已归档'

select count(distinct o.customer_id)
from biz_customer_order o
inner join biz_delivery_order d on o.delivery_id = d.delivery_id
where d.delivery_date >= #{beginDate}
  and d.delivery_date < #{endDate}
  and d.status = '已归档'

select count(*)
from biz_customer_order o
inner join biz_delivery_order d on o.delivery_id = d.delivery_id
where d.delivery_date >= #{beginDate}
  and d.delivery_date < #{endDate}

select count(distinct o.customer_id)
from biz_customer_order o
inner join biz_delivery_order d on o.delivery_id = d.delivery_id
where d.delivery_date >= #{beginDate}
  and d.delivery_date < #{endDate}
